1	package com.interview.lld.parking.service;
2	
3	import java.time.Duration;
4	import java.time.Instant;
5	import java.util.List;
6	import java.util.Map;
7	import java.util.concurrent.ConcurrentHashMap;
8	import java.util.concurrent.atomic.AtomicLong;
9	import java.util.function.Supplier;
10	
11	import com.interview.lld.parking.model.NoSpotAvailableException;
12	import com.interview.lld.parking.model.ParkingFloor;
13	import com.interview.lld.parking.model.ParkingSpot;
14	import com.interview.lld.parking.model.Ticket;
15	import com.interview.lld.parking.model.TicketNotFoundException;
16	import com.interview.lld.parking.model.Vehicle;
17	import com.interview.lld.parking.strategy.SpotAllocationStrategy;
18	
19	// ── WHY THIS CLASS ───────────────────────────────────────────────────────────
20	// The brain — the public API external code calls. It owns the floors, the
21	// open-ticket registry, and the clock and rate used to bill. It coordinates:
22	// it asks the strategy WHICH spot, then occupies it and issues a ticket; on
23	// exit it frees the spot and computes the fee. It does NOT decide which spot is
24	// best (that's the strategy) and it does NOT flip spot status directly (that's
25	// the spot's own state machine).
26	//
27	// This is the CLEAN, single-threaded-correct core: there is NOT one line of
28	// lock code in this file. The only seam is the withSpotGuard() hook — a
29	// do-nothing wrapper here that the thread-safe subclass overrides with a real
30	// per-spot lock. (This is the Template Method move.)
31	// 🎙️ "This is the orchestrator. It holds the floors and a map of open tickets.
32	//      Park = ask the strategy for a spot, occupy it, issue a ticket. Unpark =
33	//      look up the ticket, free the spot, compute the fee. Notice there are
34	//      zero locks in this file — concurrency is a separate subclass that
35	//      overrides one tiny hook."
36	public class ParkingLotService {
37	
38	    private final List<ParkingFloor> floors;
39	    private final SpotAllocationStrategy strategy;
40	
41	    // WHY: time is injected as a Supplier instead of calling Instant.now()
42	    //      inside the code. Tests pass a fake clock so we can "pretend the car
43	    //      stayed two hours" without actually waiting two hours.
44	    private final Supplier<Instant> clock;
45	
46	    // WHY: the hourly rate, in cents, used to bill at exit. Cents (an int-like
47	    //      long) avoids floating-point money bugs.
48	    private final long ratePerHourCents;
49	
50	    // WHY: the open-ticket registry — the orchestrator owns the truth about
51	    //      every car currently parked. ConcurrentHashMap so the thread-safe
52	    //      subclass can read/write it from many threads without a separate map
53	    //      lock; the clean core treats it as a plain map. Key is the spot id,
54	    //      so unpark can find and free the exact spot in O(1).
55	    private final Map<String, Ticket> openTickets = new ConcurrentHashMap<>();
56	
57	    // WHY: a counter for ticket ids (tkt-1, tkt-2...) instead of random UUIDs.
58	    //      Numbered ids make test assertions readable. Production would swap in
59	    //      a UUID. AtomicLong so id generation is safe under the subclass too.
60	    private final AtomicLong ticketCounter = new AtomicLong(0);
61	
62	    public ParkingLotService(List<ParkingFloor> floors,
63	                             SpotAllocationStrategy strategy,
64	                             Supplier<Instant> clock,
65	                             long ratePerHourCents) {
66	        this.floors = List.copyOf(floors);
67	        this.strategy = strategy;
68	        this.clock = clock;
69	        this.ratePerHourCents = ratePerHourCents;
70	    }
71	
72	    // ─── Template Method HOOK ────────────────────────────────────────────────
73	    // WHY: this wrapper does NOTHING in the clean version — it just runs the
74	    //      action. The thread-safe subclass overrides it to lock THIS spot
75	    //      around the action. Result: this whole file has no lock code, and the
76	    //      concurrency diff is one overridden method.
77	    // 🎙️ "This hook is the seam. Here it just runs the work. The thread-safe
78	    //      subclass overrides it to take the spot's own lock first. My clean
79	    //      code never mentions locks."
80	    protected <T> T withSpotGuard(ParkingSpot spot, Supplier<T> action) {
81	        return action.get();
82	    }
83	
84	    // ─── PARK ────────────────────────────────────────────────────────────────
85	    // WHY: the pipeline — find, then occupy-and-ticket as one guarded step.
86	    //   1. ask the strategy for the best free, compatible spot
87	    //   2. if none, throw the typed "lot full" error (never return null)
88	    //   3. under the spot guard: re-check it's free, occupy it, issue a ticket
89	    //   4. record the ticket in the registry and return it
90	    // The re-check inside the guard is what makes park race-safe in the
91	    // subclass: between step 1 and step 3 another thread could have taken the
92	    // spot, so we look again while holding the lock.
93	    public Ticket park(Vehicle vehicle) {
94	        if (vehicle == null) {
95	            throw new com.interview.lld.parking.model.ParkingException(
96	                "vehicle must not be null");
97	        }
98	
99	        ParkingSpot candidate = strategy.findSpot(floors, vehicle.type())
100	            .orElseThrow(() -> new NoSpotAvailableException(
101	                "no free spot for vehicle type " + vehicle.type()));
102	
103	        // WHY: the critical section is "confirm free + occupy + ticket". In the
104	        //      clean core the guard is a no-op so this just runs. In the
105	        //      subclass it runs while holding candidate's lock, so no two
106	        //      threads can both occupy the same spot.
107	        return withSpotGuard(candidate, () -> {
108	            // WHY: re-check INSIDE the guard. The strategy's answer is a hint
109	            //      that may be stale by the time we hold the lock. If the spot
110	            //      was taken meanwhile, retry the whole park once.
111	            if (!candidate.isFree()) {
112	                return park(vehicle);
113	            }
114	            candidate.occupy(vehicle);
115	            Ticket ticket = new Ticket(
116	                nextTicketId(), candidate.id(), vehicle, clock.get());
117	            openTickets.put(candidate.id(), ticket);
118	            return ticket;
119	        });
120	    }
121	
122	    // ─── UNPARK ──────────────────────────────────────────────────────────────
123	    // WHY: the completion path — look up, guard, free, bill.
124	    //   1. look up the open ticket by id; unknown id -> typed error
125	    //   2. find the spot the ticket points at
126	    //   3. under the spot guard: free the spot and drop the ticket
127	    //   4. compute and return the fee from entry time to now
128	    public long unpark(String ticketId) {
129	        if (ticketId == null) {
130	            throw new TicketNotFoundException("ticketId must not be null");
131	        }
132	
133	        // WHY: tickets are keyed by spot id in the registry, but callers hold a
134	        //      ticket id, so we scan the small open-ticket set to find it. The
135	        //      open set is bounded by the number of currently parked cars.
136	        Ticket ticket = findOpenTicketById(ticketId);
137	        if (ticket == null) {
138	            throw new TicketNotFoundException(
139	                "no open ticket with id " + ticketId);
140	        }
141	
142	        ParkingSpot spot = findSpotById(ticket.spotId());
143	
144	        withSpotGuard(spot, () -> {
145	            spot.release();
146	            // WHY: drop from the registry so the same ticket can't be unparked
147	            //      twice and the spot id is free to be re-keyed by a new park.
148	            openTickets.remove(spot.id());
149	            return null;
150	        });
151	
152	        return computeFee(ticket.entryTime(), clock.get());
153	    }
154	
155	    // ─── QUERIES ─────────────────────────────────────────────────────────────
156	    // WHY: how many spots are currently taken. Reads the registry size in O(1)
157	    //      — the registry IS the set of occupied spots, so no scanning.
158	    public int occupiedCount() {
159	        return openTickets.size();
160	    }
161	
162	    // WHY: count free spots compatible with a vehicle type — used by the demo
163	    //      and tests to confirm the lot drains and refills correctly.
164	    public long availableCountFor(
165	            com.interview.lld.parking.model.VehicleType type) {
166	        return floors.stream()
167	            .flatMap(f -> f.spots().stream())
168	            .filter(ParkingSpot::isFree)
169	            .filter(s -> type.fits(s.size()))
170	            .count();
171	    }
172	
173	    // ─── HELPERS ─────────────────────────────────────────────────────────────
174	    // WHY: generate the next readable ticket id. Atomic so even the subclass's
175	    //      many threads each get a distinct id.
176	    private String nextTicketId() {
177	        return "tkt-" + ticketCounter.incrementAndGet();
178	    }
179	
180	    // WHY: scan the open tickets for the one with this id. The set is small
181	    //      (only currently-parked cars), so the scan is cheap. We key the map
182	    //      by spot id for O(1) unpark-by-spot, and accept O(open) for the
183	    //      by-ticket-id lookup since the open set is bounded by lot capacity.
184	    private Ticket findOpenTicketById(String ticketId) {
185	        for (Ticket t : openTickets.values()) {
186	            if (t.id().equals(ticketId)) {
187	                return t;
188	            }
189	        }
190	        return null;
191	    }
192	
193	    // WHY: locate the physical spot a ticket refers to. If the spot id on a
194	    //      live ticket has no matching spot, the lot config is corrupt — a
195	    //      typed error beats a silent null.
196	    private ParkingSpot findSpotById(String spotId) {
197	        for (ParkingFloor floor : floors) {
198	            for (ParkingSpot spot : floor.spots()) {
199	                if (spot.id().equals(spotId)) {
200	                    return spot;
201	                }
202	            }
203	        }
204	        throw new TicketNotFoundException(
205	            "ticket points at unknown spot " + spotId);
206	    }
207	
208	    // WHY: bill by the hour, rounding any partial hour UP — standard parking
209	    //      practice. A 61-minute stay bills two hours. Done in cents to avoid
210	    //      floating-point money errors. Minimum one hour for any stay.
211	    // ⚠️ FOLLOW-UP: "Why round up?"
212	    //    → "Real lots bill per started hour — five minutes over still costs the
213	    //       next hour. Rounding up is the correct domain behavior, and it also
214	    //       guarantees every stay bills at least the one-hour minimum."
215	    private long computeFee(Instant entry, Instant exit) {
216	        Duration stay = Duration.between(entry, exit);
217	        long minutes = Math.max(0, stay.toMinutes());
218	        long hours = (minutes + 59) / 60;     // round up partial hours
219	        if (hours == 0) {
220	            hours = 1;                         // minimum one hour
221	        }
222	        return hours * ratePerHourCents;
223	    }
224	}
