3	import java.time.Instant;
4	import java.util.List;
5	import java.util.concurrent.locks.ReentrantLock;
6	import java.util.function.Supplier;
7	
8	import com.interview.lld.parking.model.ParkingFloor;
9	import com.interview.lld.parking.model.ParkingSpot;
10	import com.interview.lld.parking.strategy.SpotAllocationStrategy;
11	
12	// ── WHY THIS CLASS ───────────────────────────────────────────────────────────
13	// The thread-safe version. It changes EXACTLY ONE thing: it overrides the
14	// withSpotGuard hook to take the spot's OWN lock around the check-and-occupy.
15	// Every other line of behavior is inherited unchanged from the clean service.
16	// The diff between "clean" and "thread-safe" is this one method.
17	//
18	// PER-SPOT FINE-GRAINED LOCKS: each ParkingSpot carries its own ReentrantLock.
19	// park() locks that one spot before marking it occupied, so two threads can
20	// never both occupy the same spot — that's the double-allocation race, gone.
21	// Two threads parking in DIFFERENT spots take DIFFERENT locks, so they run
22	// fully in parallel — no global bottleneck.
23	// 🎙️ "Thread safety is one overridden method. I lock the spot we're about to
24	//      take, not a global lock. Two cars going for two different spots never
25	//      wait on each other — they hold different locks. Only two cars fighting
26	//      over the SAME spot serialize, and the loser sees it's taken and the
27	//      re-check in park() sends it to find another spot."
28	public class ThreadSafeParkingLotService extends ParkingLotService {
29	
30	    public ThreadSafeParkingLotService(List<ParkingFloor> floors,
31	                                       SpotAllocationStrategy strategy,
32	                                       Supplier<Instant> clock,
33	                                       long ratePerHourCents) {
34	        super(floors, strategy, clock, ratePerHourCents);
35	    }
36	
37	    // ─── The ONLY override ───────────────────────────────────────────────────
38	    // WHY: take the spot's own lock, run the action, always unlock. A
39	    //      ReentrantLock so the same thread can safely re-enter if a guarded
40	    //      method ever calls another guarded method on the same spot. The
41	    //      lock/try/finally is the textbook safe pattern — unlock always runs,
42	    //      even if the action throws.
43	    // ⚠️ FOLLOW-UP: "Why per-spot locks and not one lock for the whole lot?"
44	    //    → "One global lock is correct but kills throughput — every park in the
45	    //       whole building serializes through one bottleneck. Per-spot locks
46	    //       let a hundred cars park into a hundred different spots at once. Only
47	    //       two cars contending for the same spot ever wait, and that wait is
48	    //       microseconds."
49	    @Override
50	    protected <T> T withSpotGuard(ParkingSpot spot, Supplier<T> action) {
51	        ReentrantLock lock = spot.lock();
52	        lock.lock();
53	        try {
54	            return action.get();
55	        } finally {
56	            lock.unlock();
57	        }
58	    }
59	}
