156	    // ─── Idempotency of spot.release ───────────────────────────────────────────
157	    @Test
158	    void releaseOnFreeSpotIsNoOp() {
159	        ParkingSpot spot = new ParkingSpot("L1-1", 1, SpotSize.LARGE);
