168	    // ─── Concurrency: the double-allocation race ───────────────────────────────
169	    @Test
170	    void concurrentParkNeverDoubleAllocatesSameSpot() throws Exception {
171	        int threads = 50, capacity = 5;
172	
173	        // Lot with exactly `capacity` LARGE spots — the precise scarce resource.
174	        List<ParkingSpot> spots = new ArrayList<>();
175	        for (int i = 0; i < capacity; i++) {
176	            spots.add(new ParkingSpot("L1-" + i, 1, SpotSize.LARGE));
177	        }
178	        ThreadSafeParkingLotService lot = new ThreadSafeParkingLotService(
179	            List.of(new ParkingFloor(1, spots)), new BestFitNearestStrategy(), clock, 200);
180	
181	        CyclicBarrier barrier = new CyclicBarrier(threads);   // stampede gate
182	        AtomicInteger wins = new AtomicInteger(0);
183	        AtomicInteger fulls = new AtomicInteger(0);
184	        AtomicInteger unexpected = new AtomicInteger(0);
185	        var wonSpots = ConcurrentHashMap.<String>newKeySet();
186	        ExecutorService pool = Executors.newFixedThreadPool(threads);
187	
188	        for (int i = 0; i < threads; i++) {
189	            final int id = i;
190	            pool.submit(() -> {
191	                try {
192	                    barrier.await();          // all 50 hit park() at the same moment
193	                    Ticket t = lot.park(new Vehicle("C-" + id, VehicleType.CAR));
194	                    wins.incrementAndGet();
195	                    wonSpots.add(t.spotId());
196	                } catch (NoSpotAvailableException e) {
197	                    fulls.incrementAndGet();
198	                } catch (Exception e) {
199	                    unexpected.incrementAndGet();
200	                }
201	            });
202	        }
203	        pool.shutdown();
204	        assertTrue(pool.awaitTermination(15, TimeUnit.SECONDS));
205	
206	        // STRICT post-state assertions:
207	        assertEquals(capacity, wins.get(), "exactly capacity threads parked");
208	        assertEquals(capacity, wonSpots.size(),
209	            "every win is a DIFFERENT spot — no double-allocation");
210	        assertEquals(threads - capacity, fulls.get(),
211	            "all others got the typed full error");
212	        assertEquals(0, unexpected.get(), "no surprise exceptions");
213	
214	        // Count occupied spots via the entity status, not a service-side set.
215	        long occupied = spots.stream().filter(s -> s.status() == SpotStatus.OCCUPIED).count();
216	        assertEquals(capacity, occupied, "exactly capacity spots OCCUPIED");
217	        assertEquals(capacity, lot.occupiedCount(), "registry matches occupied spots");
218	    }
