220	    @Test
221	    void concurrentParkUnparkChurnLeavesConsistentState() throws Exception {
222	        // Park and unpark repeatedly across many threads; the lot must end
223	        // empty with every spot FREE — proving no spot is leaked or stranded.
224	        int threads = 20;
225	        List<ParkingSpot> spots = new ArrayList<>();
226	        for (int i = 0; i < 10; i++) {
227	            spots.add(new ParkingSpot("L1-" + i, 1, SpotSize.LARGE));
228	        }
229	        ThreadSafeParkingLotService lot = new ThreadSafeParkingLotService(
230	            List.of(new ParkingFloor(1, spots)), new BestFitNearestStrategy(), clock, 200);
231	
232	        ExecutorService pool = Executors.newFixedThreadPool(threads);
233	        for (int i = 0; i < threads; i++) {
234	            pool.submit(() -> {
