package com.interview.lld.parking;

import java.time.Instant;
import java.util.ArrayList;
import java.util.List;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.concurrent.TimeUnit;
import java.util.concurrent.atomic.AtomicInteger;
import java.util.function.Supplier;

import com.interview.lld.parking.model.*;
import com.interview.lld.parking.service.ThreadSafeParkingLotService;
import com.interview.lld.parking.strategy.BestFitNearestStrategy;

// Instrumented subclass: count how many spot locks THIS thread holds at once.
public class LockDepthVerify {
    static final ThreadLocal<Integer> depth = ThreadLocal.withInitial(() -> 0);
    static final AtomicInteger maxDepth = new AtomicInteger(0);

    public static void main(String[] args) throws Exception {
        Supplier<Instant> clock = () -> Instant.parse("2026-06-21T08:00:00Z");
        List<ParkingSpot> spots = new ArrayList<>();
        for (int i = 0; i < 8; i++) spots.add(new ParkingSpot("L1-" + i, 1, SpotSize.LARGE));
        var lot = new ThreadSafeParkingLotService(
                List.of(new ParkingFloor(1, spots)), new BestFitNearestStrategy(), clock, 200) {
            @Override
            protected <T> T withSpotGuard(ParkingSpot spot, Supplier<T> action) {
                int d = depth.get() + 1;
                depth.set(d);
                maxDepth.accumulateAndGet(d, Math::max);
                try {
                    return super.withSpotGuard(spot, action);
                } finally {
                    depth.set(depth.get() - 1);
                }
            }
        };

        int threads = 128;
        ExecutorService pool = Executors.newFixedThreadPool(threads);
        for (int t = 0; t < threads; t++) {
            pool.submit(() -> {
                for (int r = 0; r < 30000 / threads + 1; r++) {
                    try {
                        Ticket tk = lot.park(new Vehicle("X", VehicleType.CAR));
                        lot.unpark(tk.id());
                    } catch (NoSpotAvailableException ignored) { }
                }
            });
        }
        pool.shutdown();
        boolean done = pool.awaitTermination(60, TimeUnit.SECONDS);
        long occupied = spots.stream().filter(s -> s.status() == SpotStatus.OCCUPIED).count();
        System.out.println("terminated=" + done
                + " MAX simultaneous spot-locks held=" + maxDepth.get()
                + " occupied-after=" + occupied
                + " registry=" + lot.occupiedCount());
    }
}
